return [{ json: memo_v2 }];

const memo = $node["Update Memo v2"].json;

const services = memo.services_supported || [];
const after_hours = memo.after_hours_routing || "voicemail";

return [
{
json: {
agent_name: memo.company_name + " Voice Agent",
company: memo.company_name,

voice_style: "friendly and professional",

system_prompt: `
You are a voice assistant for ${memo.company_name}.

Services supported:
${services.join(", ")}

During business hours route calls normally.

After hours:
- if emergency transfer to dispatch
- otherwise send to ${after_hours}
`,

routing: {
emergency: "dispatch",
non_emergency: "office",
after_hours: after_hours
},

version: "v2"
}
}
];

const spec = $input.first().json;

const changes = [];

if (spec.routing) {
  changes.push("Configured routing rules");
}

if (spec.voice_style) {
  changes.push("Defined voice assistant style");
}

changes.push("Generated updated agent configuration");

return [
  {
    json: {
      version: "v2",
      agent_name: spec.agent_name,
      changes
    }
  }
];

const file = $input.first().binary.data;
const transcript = Buffer.from(file.data, 'base64').toString();

return [
  {
    json: {
      transcript: transcript
    }
  }
];

const transcript = $json.transcript.toLowerCase();

let company_name = "Unknown Company";
let services_supported = [];
let emergency_definition = "urgent service issues";

if (transcript.includes("ben")) {
  company_name = "Ben's Electric";
}

if (transcript.includes("sprinkler")) {
  services_supported.push("sprinkler services");
}

if (transcript.includes("fire alarm")) {
  services_supported.push("fire alarm inspections");
}

if (services_supported.length === 0) {
  services_supported.push("general electrical services");
}

return [
{
json: {
company_name: company_name,
services_supported: services_supported,
emergency_definition: emergency_definition,
notes: transcript
}
}
];

const memo = $node["Generate Account Memo v1"].json;

const services = memo.services_supported || [];

return [
{
json: {
agent_name: memo.company_name + " Voice Agent",
company: memo.company_name,

voice_style: "friendly and professional",

system_prompt: `
You are a voice assistant for ${memo.company_name}.

Services supported:
${services.join(", ")}

If the caller reports an emergency, transfer to dispatch.
Otherwise route the call appropriately.
`,

routing: {
emergency: "dispatch",
non_emergency: "office",
after_hours: "voicemail"
},

version: "v1"
}
}
];
